diff --git a/packages/svelte/src/internal/client/reactivity/batch.js b/packages/svelte/src/internal/client/reactivity/batch.js
index 1d08b5c3d..7e51a7da0 100644
--- a/packages/svelte/src/internal/client/reactivity/batch.js
+++ b/packages/svelte/src/internal/client/reactivity/batch.js
@@ -300,14 +300,13 @@ export class Batch {
 	deactivate() {
 		current_batch = null;

-		for (const update of effect_pending_updates) {
-			effect_pending_updates.delete(update);
-			update();
-
-			if (current_batch !== null) {
-				// only do one at a time
-				break;
-			}
+		// Apply all pending effect updates. These updates can schedule effects
+		// into fresh batches; we need to drain the queue so `flushSync()` can
+		// reliably observe them.
+		while (effect_pending_updates.size > 0) {
+			const updates = Array.from(effect_pending_updates);
+			effect_pending_updates.clear();
+			for (const update of updates) update();
 		}
 	}

@@ -452,17 +451,37 @@ export function flushSync(fn) {
 	var result;

 	const batch = Batch.ensure(false);
+	batch.activate();

-	if (fn) {
-		batch.flush_effects();
+	// Flush any already-queued effects before optionally running `fn`
+	batch.flush_effects();

+	if (fn) {
 		result = fn();
+		// Apply effects scheduled by work done in `fn`
+		batch.flush_effects();
 	}

 	while (true) {
 		flush_tasks();

+		// If `deactivate()` previously scheduled updates into a new batch,
+		// ensure we process them before checking for completion.
+		if (current_batch !== null && queued_root_effects.length > 0) {
+			current_batch.flush_effects();
+		}
+
 		if (queued_root_effects.length === 0) {
+			// Ensure any pending effect updates (from state writes) are applied
+			// before concluding that there is nothing left to flush.
+			batch.deactivate();
+
+			// `deactivate` can schedule effects by applying queued updates.
+			if (queued_root_effects.length > 0) {
+				batch.flush_effects();
+				continue;
+			}
+
 			if (batch === current_batch) {
 				batch.flush();
 			}
