content.content:
     1→/** @import { Derived, Effect, Source } from '#client' */
     2→import {
     3→	BLOCK_EFFECT,
     4→	BRANCH_EFFECT,
     5→	CLEAN,
     6→	DESTROYED,
     7→	DIRTY,
     8→	EFFECT,
     9→	ASYNC,
    10→	INERT,
    11→	RENDER_EFFECT,
    12→	ROOT_EFFECT,
    13→	USER_EFFECT
    14→} from '#client/constants';
    15→import { async_mode_flag } from '../../flags/index.js';
    16→import { deferred, define_property } from '../../shared/utils.js';
    17→import { get_pending_boundary } from '../dom/blocks/boundary.js';
    18→import {
    19→	active_effect,
    20→	is_dirty,
    21→	is_updating_effect,
    22→	set_is_updating_effect,
    23→	set_signal_status,
    24→	update_effect,
    25→	write_version
    26→} from '../runtime.js';
    27→import * as e from '../errors.js';
    28→import { flush_tasks } from '../dom/task.js';
    29→import { DEV } from 'esm-env';
    30→import { invoke_error_boundary } from '../error-handling.js';
    31→import { old_values } from './sources.js';
    32→import { unlink_effect } from './effects.js';
    33→import { unset_context } from './async.js';
    34→
    35→/** @type {Set<Batch>} */
    36→const batches = new Set();
    37→
    38→/** @type {Batch | null} */
    39→export let current_batch = null;
    40→
    41→/**
    42→ * When time travelling, we re-evaluate deriveds based on the temporary
    43→ * values of their dependencies rather than their actual values, and cache
    44→ * the results in this map rather than on the deriveds themselves
    45→ * @type {Map<Derived, any> | null}
    46→ */
    47→export let batch_deriveds = null;
    48→
    49→/** @type {Effect[]} Stack of effects, dev only */
    50→export let dev_effect_stack = [];
    51→
    52→/** @type {Set<() => void>} */
    53→export let effect_pending_updates = new Set();
    54→
    55→/** @type {Effect[]} */
    56→let queued_root_effects = [];
    57→
    58→/** @type {Effect | null} */
    59→let last_scheduled_effect = null;
    60→
    61→let is_flushing = false;
    62→
    63→export class Batch {
    64→	/**
    65→	 * The current values of any sources that are updated in this batch
    66→	 * They keys of this map are identical to `this.#previous`
    67→	 * @type {Map<Source, any>}
    68→	 */
    69→	#current = new Map();
    70→
    71→	/**
    72→	 * The values of any sources that are updated in this batch _before_ those updates took place.
    73→	 * They keys of this map are identical to `this.#current`
    74→	 * @type {Map<Source, any>}
    75→	 */
    76→	#previous = new Map();
    77→
    78→	/**
    79→	 * When the batch is committed (and the DOM is updated), we need to remove old branches
    80→	 * and append new ones by calling the functions added inside (if/each/key/etc) blocks
    81→	 * @type {Set<() => void>}
    82→	 */
    83→	#callbacks = new Set();
    84→
    85→	/**
    86→	 * The number of async effects that are currently in flight
    87→	 */
    88→	#pending = 0;
    89→
    90→	/**
    91→	 * A deferred that resolves when the batch is committed, used with `settled()`
    92→	 * TODO replace with Promise.withResolvers once supported widely enough
    93→	 * @type {{ promise: Promise<void>, resolve: (value?: any) => void, reject: (reason: unknown) => void } | null}
    94→	 */
    95→	#deferred = null;
    96→
    97→	/**
    98→	 * True if an async effect inside this batch resolved and
    99→	 * its parent branch was already deleted
   100→	 */
   101→	#neutered = false;
   102→
   103→	/**
   104→	 * Async effects (created inside `async_derived`) encountered during processing.
   105→	 * These run after the rest of the batch has updated, since they should
   106→	 * always have the latest values
   107→	 * @type {Effect[]}
   108→	 */
   109→	#async_effects = [];
   110→
   111→	/**
   112→	 * The same as `#async_effects`, but for effects inside a newly-created
   113→	 * `<svelte:boundary>` — these do not prevent the batch from committing
   114→	 * @type {Effect[]}
   115→	 */
   116→	#boundary_async_effects = [];
   117→
   118→	/**
   119→	 * Template effects and `$effect.pre` effects, which run when
   120→	 * a batch is committed
   121→	 * @type {Effect[]}
   122→	 */
   123→	#render_effects = [];
   124→
   125→	/**
   126→	 * The same as `#render_effects`, but for `$effect` (which runs after)
   127→	 * @type {Effect[]}
   128→	 */
   129→	#effects = [];
   130→
   131→	/**
   132→	 * Block effects, which may need to re-run on subsequent flushes
   133→	 * in order to update internal sources (e.g. each block items)
   134→	 * @type {Effect[]}
   135→	 */
   136→	#block_effects = [];
   137→
   138→	/**
   139→	 * A set of branches that still exist, but will be destroyed when this batch
   140→	 * is committed — we skip over these during `process`
   141→	 * @type {Set<Effect>}
   142→	 */
   143→	skipped_effects = new Set();
   144→
   145→	/**
   146→	 *
   147→	 * @param {Effect[]} root_effects
   148→	 */
   149→	#process(root_effects) {
   150→		queued_root_effects = [];
   151→
   152→		/** @type {Map<Source, { v: unknown, wv: number }> | null} */
   153→		var current_values = null;
   154→
   155→		// if there are multiple batches, we are 'time travelling' —
   156→		// we need to undo the changes belonging to any batch
   157→		// other than the current one
   158→		if (batches.size > 1) {
   159→			current_values = new Map();
   160→			batch_deriveds = new Map();
   161→
   162→			for (const [source, current] of this.#current) {
   163→				current_values.set(source, { v: source.v, wv: source.wv });
   164→				source.v = current;
   165→			}
   166→
   167→			for (const batch of batches) {
   168→				if (batch === this) continue;
   169→
   170→				for (const [source, previous] of batch.#previous) {
   171→					if (!current_values.has(source)) {
   172→						current_values.set(source, { v: source.v, wv: source.wv });
   173→						source.v = previous;
   174→					}
   175→				}
   176→			}
   177→		}
   178→
   179→		for (const root of root_effects) {
   180→			this.#traverse_effect_tree(root);
   181→		}
   182→
   183→		// if we didn't start any new async work, and no async work
   184→		// is outstanding from a previous flush, commit
   185→		if (this.#async_effects.length === 0 && this.#pending === 0) {
   186→			var render_effects = this.#render_effects;
   187→			var effects = this.#effects;
   188→
   189→			this.#render_effects = [];
   190→			this.#effects = [];
   191→			this.#block_effects = [];
   192→
   193→			this.#commit();
   194→
   195→			flush_queued_effects(render_effects);
   196→			flush_queued_effects(effects);
   197→
   198→			this.#deferred?.resolve();
   199→		} else {
   200→			// otherwise mark effects clean so they get scheduled on the next run
   201→			for (const e of this.#render_effects) set_signal_status(e, CLEAN);
   202→			for (const e of this.#effects) set_signal_status(e, CLEAN);
   203→			for (const e of this.#block_effects) set_signal_status(e, CLEAN);
   204→		}
   205→
   206→		if (current_values) {
   207→			for (const [source, { v, wv }] of current_values) {
   208→				// reset the source to the current value (unless
   209→				// it got a newer value as a result of effects running)
   210→				if (source.wv <= wv) {
   211→					source.v = v;
   212→				}
   213→			}
   214→
   215→			batch_deriveds = null;
   216→		}
   217→
   218→		for (const effect of this.#async_effects) {
   219→			update_effect(effect);
   220→		}
   221→
   222→		for (const effect of this.#boundary_async_effects) {
   223→			update_effect(effect);
   224→		}
   225→
   226→		this.#async_effects = [];
   227→		this.#boundary_async_effects = [];
   228→	}
   229→
   230→	/**
   231→	 * Traverse the effect tree, executing effects or stashing
   232→	 * them for later execution as appropriate
   233→	 * @param {Effect} root
   234→	 */
   235→	#traverse_effect_tree(root) {
   236→		root.f ^= CLEAN;
   237→
   238→		var effect = root.first;
   239→
   240→		while (effect !== null) {
   241→			var flags = effect.f;
   242→			var is_branch = (flags & (BRANCH_EFFECT | ROOT_EFFECT)) !== 0;
   243→			var is_skippable_branch = is_branch && (flags & CLEAN) !== 0;
   244→
   245→			var skip = is_skippable_branch || (flags & INERT) !== 0 || this.skipped_effects.has(effect);
   246→
   247→			if (!skip && effect.fn !== null) {
   248→				if (is_branch) {
   249→					effect.f ^= CLEAN;
   250→				} else if ((flags & EFFECT) !== 0) {
   251→					this.#effects.push(effect);
   252→				} else if (async_mode_flag && (flags & RENDER_EFFECT) !== 0) {
   253→					this.#render_effects.push(effect);
   254→				} else if (is_dirty(effect)) {
   255→					if ((flags & ASYNC) !== 0) {
   256→						var effects = effect.b?.pending ? this.#boundary_async_effects : this.#async_effects;
   257→						effects.push(effect);
   258→					} else {
   259→						if ((effect.f & BLOCK_EFFECT) !== 0) this.#block_effects.push(effect);
   260→						update_effect(effect);
   261→					}
   262→				}
   263→
   264→				var child = effect.first;
   265→
   266→				if (child !== null) {
   267→					effect = child;
   268→					continue;
   269→				}
   270→			}
   271→
   272→			var parent = effect.parent;
   273→			effect = effect.next;
   274→
   275→			while (effect === null && parent !== null) {
   276→				effect = parent.next;
   277→				parent = parent.parent;
   278→			}
   279→		}
   280→	}
   281→
   282→	/**
   283→	 * Associate a change to a given source with the current
   284→	 * batch, noting its previous and current values
   285→	 * @param {Source} source
   286→	 * @param {any} value
   287→	 */
   288→	capture(source, value) {
   289→		if (!this.#previous.has(source)) {
   290→			this.#previous.set(source, value);
   291→		}
   292→
   293→		this.#current.set(source, source.v);
   294→	}
   295→
   296→	activate() {
   297→		current_batch = this;
   298→	}
   299→
   300→	deactivate() {
   301→		current_batch = null;
   302→
   303→		for (const update of effect_pending_updates) {
   304→			effect_pending_updates.delete(update);
   305→			update();
   306→
   307→			if (current_batch !== null) {
   308→				// only do one at a time
   309→				break;
   310→			}
   311→		}
   312→	}
   313→
   314→	neuter() {
   315→		this.#neutered = true;
   316→	}
   317→
   318→	flush() {
   319→		if (queued_root_effects.length > 0) {
   320→			this.flush_effects();
   321→		} else {
   322→			this.#commit();
   323→		}
   324→
