import { flushSync } from 'svelte';
import { effect_root, effect } from './effects.js';
import { state, set } from './sources.js';

describe('rune testing', () => {
	test('flushSync runs queued $effect in plain test files', () => {
		const log = state<number[]>([]);
		const count = state(0);

		effect_root(() => {
			// create a deferred user effect (like `$effect(() => ...)`)
