import { describe, expect, test } from 'vitest';
import { flushSync } from './batch.js';
import { effect_root, effect } from './effects.js';
import { state, set } from './sources.js';

describe('rune testing', () => {
	test('flushSync runs queued $effect in plain test files', () => {
		const log = state<number[]>([]);
		const count = state(0);

		effect_root(() => {
			// create a deferred user effect (like `$effect(() => ...)`)
			effect(() => {
				// eslint-disable-next-line @typescript-eslint/no-unused-expressions
				count.v;
				log.v = [...log.v, count.v];
			});
		});

		flushSync();
		expect(log.v).toEqual([0]);

		set(count, 1);
		flushSync();
		expect(log.v).toEqual([0, 1]);
	});
});

