			// if the derived is dirty, or depends on the values that just changed, re-execute
			if ((derived.f & CLEAN) !== 0 || depends_on_old_values(derived)) {
				value = execute_derived(derived);
			}

			old_values.set(derived, value);

			return value;
		}
