	capture(source, value) {
		if (!this.#previous.has(source)) {
			this.#previous.set(source, value);
		}

		this.#current.set(source, source.v);
	}

	activate() {
		current_batch = this;
	}

	deactivate() {
		current_batch = null;

		// Apply all pending effect updates. These updates can schedule effects
		// into fresh batches; we need to drain the queue so `flushSync()` can
		// reliably observe them.
		while (effect_pending_updates.size > 0) {
			const updates = Array.from(effect_pending_updates);
			effect_pending_updates.clear();
			for (const update of updates) update();
		}
	}

	neuter() {
		this.#neutered = true;
	}

	flush() {
		if (queued_root_effects.length > 0) {
			this.flush_effects();
		} else {
			this.#commit();
		}

