import { expect, test } from 'vitest';
import { flushSync } from './batch.js';
import { effect_root, effect } from './effects.js';
import { state, set } from './sources.js';

test('flushSync flushes effects scheduled by state writes', () => {
	const count = state(0);
	const log: number[] = [];

	effect_root(() => {
		effect(() => {
			// eslint-disable-next-line @typescript-eslint/no-unused-expressions
			count.v;
			log.push(count.v);
		});
	});

	flushSync();
	expect(log).toEqual([0]);

	flushSync(() => set(count, 1));
	expect(log).toEqual([0, 1]);
});

