import { expect, test } from 'vitest';
import { flushSync } from './batch.js';
import { push, pop } from '../context.js';
import { effect_root, effect } from './effects.js';
import { state } from './sources.js';

test('flushSync flushes effects scheduled by state writes (runes context)', () => {
	push({}, true);
	try {
		const count = state(0);
		const log: number[] = [];

		const cleanup = effect_root(() => {
			effect(() => {
				log.push(count.v);
			});
		});

		flushSync();
		expect(log).toEqual([0]);

		flushSync(() => {
			// This assignment mimics `$state` reassignment in `.svelte.test.js`
			count.v = 1;
		});
		expect(log).toEqual([0, 1]);

		cleanup();
	} finally {
		pop();
	}
});

