import { expect, test } from 'vitest';
import { flushSync } from './batch.js';
import { effect_root, effect } from './effects.js';
import { state, set } from './sources.js';
import { push, pop } from '../context.js';

// Regression test for Svelte 5 rune-effect testing:
// after assigning to a $state variable and calling flushSync(), a queued $effect
// should run synchronously (as documented).

test('flushSync flushes queued effects after state assignment (runes context)', () => {
	push({}, true);
	try {
		const count = state(0);
		const log: number[] = [];

		pop();

		const cleanup = effect_root(() => {
			effect(() => {
				log.push(count.v);
			});
		});

		flushSync();
		expect(log).toEqual([0]);

		// Mimic `$state` reassignment (compiled code uses `set`)
		set(count, 1);
		flushSync();
		expect(log).toEqual([0, 1]);

		cleanup();
	} finally {
		pop();
	}
});

